     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→
     7→	"github.com/sentioxyz/releaseguard/internal/models"
     8→)
     9→
    10→// ReleasesStore defines the persistence operations for releases (read-only).
    11→type ReleasesStore interface {
    12→	ListReleasesBySource(ctx context.Context, sourceID string, page, perPage int) ([]models.Release, int, error)
    13→	ListReleasesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Release, int, error)
    14→	GetRelease(ctx context.Context, id string) (*models.Release, error)
    15→}
    16→
    17→// ReleasesHandler implements HTTP handlers for the /releases resource.
    18→type ReleasesHandler struct {
    19→	store ReleasesStore
    20→}
    21→
    22→// NewReleasesHandler returns a new ReleasesHandler.
    23→func NewReleasesHandler(store ReleasesStore) *ReleasesHandler {
    24→	return &ReleasesHandler{store: store}
    25→}
    26→
    27→// ListBySource handles GET /sources/{id}/releases — returns releases for a specific source.
    28→func (h *ReleasesHandler) ListBySource(w http.ResponseWriter, r *http.Request) {
    29→	sourceID := r.PathValue("id")
    30→	if sourceID == "" {
    31→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Source ID is required")
    32→		return
    33→	}
    34→	page, perPage := ParsePagination(r)
    35→	releases, total, err := h.store.ListReleasesBySource(r.Context(), sourceID, page, perPage)
    36→	if err != nil {
    37→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    38→		return
    39→	}
    40→	if releases == nil {
    41→		releases = []models.Release{}
    42→	}
    43→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    44→}
    45→
    46→// ListByProject handles GET /projects/{projectId}/releases — returns releases for all sources in a project.
    47→func (h *ReleasesHandler) ListByProject(w http.ResponseWriter, r *http.Request) {
    48→	projectID := r.PathValue("projectId")
    49→	if projectID == "" {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    51→		return
    52→	}
    53→	page, perPage := ParsePagination(r)
    54→	releases, total, err := h.store.ListReleasesByProject(r.Context(), projectID, page, perPage)
    55→	if err != nil {
    56→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    57→		return
    58→	}
    59→	if releases == nil {
    60→		releases = []models.Release{}
    61→	}
    62→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    63→}
    64→
    65→// Get handles GET /releases/{id} — returns a single release.
    66→func (h *ReleasesHandler) Get(w http.ResponseWriter, r *http.Request) {
    67→	id := r.PathValue("id")
    68→	if id == "" {
    69→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Release ID is required")
    70→		return
    71→	}
    72→	rel, err := h.store.GetRelease(r.Context(), id)
    73→	if err != nil {
    74→		RespondError(w, r, http.StatusNotFound, "not_found", "Release not found")
    75→		return
    76→	}
    77→	RespondJSON(w, r, http.StatusOK, rel)
    78→}
