  _projectName?: string;
  _projectId?: string;
  _provider?: string;
  _repository?: string;
}

const PER_PAGE = 15;

function getProviderUrl(
  provider: string,
  repository: string,
  version: string
): string | null {
  switch (provider) {
    case "github":
      return `https://github.com/${repository}/releases/tag/${version}`;
    case "dockerhub":
      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    default:
      return null;
